package com.example.myapp.deeplink

import android.app.Activity
import android.content.ActivityNotFoundException
import android.content.Context
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.core.net.toUri

object DeepLinkHandler {
    const val SCHEME = "myapp"

    fun handle(context: Context, uri: Uri?): Boolean {
        if (uri == null) return false
        if (!uri.isHierarchical) return false
        if (!uri.scheme.equals(SCHEME, ignoreCase = true)) return false

        val segments = uri.pathSegments
        if (segments.isEmpty()) {
            openAppHome(context)
            return true
        }

        return when (segments[0].lowercase()) {
            "profile" -> {
                val userId = segments.getOrNull(1)?.takeIf { it.isNotBlank() }
                if (userId != null) {
                    openProfile(context, userId, uri)
                    true
                } else {
                    openAppHome(context)
                    true
                }
            }
            "payment" -> {
                val action = segments.getOrNull(1)?.lowercase()
                if (action == "confirm") {
                    openPaymentConfirm(context, uri)
                    true
                } else {
                    openAppHome(context)
                    true
                }
            }
            else -> {
                openAppHome(context)
                true
            }
        }
    }

    private fun openProfile(context: Context, userId: String, originalUri: Uri) {
        val intent = Intent(context, ProfileActivity::class.java)
            .putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            .putExtra(EXTRA_ORIGINAL_URI, originalUri.toString())
        startActivitySafely(context, intent)
    }

    private fun openPaymentConfirm(context: Context, originalUri: Uri) {
        val intent = Intent(context, PaymentConfirmActivity::class.java)
            .putExtra(EXTRA_ORIGINAL_URI, originalUri.toString())
        startActivitySafely(context, intent)
    }

    private fun openAppHome(context: Context) {
        val intent = Intent(context, MainActivity::class.java)
        startActivitySafely(context, intent)
    }

    private fun startActivitySafely(context: Context, intent: Intent) {
        val finalIntent = intent.apply {
            addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP)
            if (context !is Activity) addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        }
        try {
            context.startActivity(finalIntent)
        } catch (_: ActivityNotFoundException) {
        }
    }

    const val EXTRA_ORIGINAL_URI = "extra_original_uri"
}

